I use [Catch all routes](https://nextjs.org/docs/routing/dynamic-routes#catch-all-routes) in the File **pages/[[slug]].tsx**

I request the data from an API made with Strapi, this is the way I do the generation of the pages

## getStaticPaths
```ts
export const getStaticPaths: GetStaticPaths = async ({ defaultLocale }) => {
	const paths = await getAllPagePaths();

	return {
		fallback: 'blocking',
		paths: paths.map((route) => {
			const routePath = route.locale === defaultLocale ? route.path : route.path.substring(3);

			return {
				locale: route.locale,
				params: {
					path: routePath.split('/').filter((part) => part),
				},
			};
		}),
	};
};
```
## getStaticProps
```ts
export const getStaticProps: GetStaticProps<Props, IStaticPathParams> = async (context) => {
	const { params, locale, defaultLocale } = context;
	const path = getFormatPath(locale, params);

	const content: IPageContent | null = await pageContentGetPageByUrl(path);

	if (!content) {
		return {
			notFound: true,
			revalidate: Number(process.env.NEXT_REVALIDATE_TIME || 10),
		};
	}

	return {
		props: {
			content,
			locale,
			path,
		},
		revalidate: Number(process.env.NEXT_REVALIDATE_TIME || 10),
	};
};
```

